import {
  afterNextRender,
  ChangeDetectionStrategy,
  Component,
  computed,
  ElementRef,
  inject,
  input,
  signal,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import {
  dividerVariants,
  type HbDividerOrientation,
  type HbDividerVariant,
} from './divider.variants';

@Component({
  selector: 'hb-divider, [hb-divider]',
  template: `
    @if (hasLabel()) {
      <span class="shrink-0 px-3 text-xs text-muted-foreground">
        @if (hbLabel()) {
          {{ hbLabel() }}
        } @else {
          <ng-content />
        }
      </span>
    }
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    role: 'separator',
    '[attr.aria-orientation]': 'hbOrientation()',
    '[attr.data-slot]': "'divider'",
  },
  exportAs: 'hbDivider',
})
export class HbDividerComponent {
  private readonly host = inject<ElementRef<HTMLElement>>(ElementRef);

  readonly hbOrientation = input<HbDividerOrientation>('horizontal');
  readonly hbVariant = input<HbDividerVariant>('solid');
  readonly hbLabel = input('');
  readonly class = input<ClassValue>('');

  private readonly projectedLabel = signal(false);
  protected readonly hasLabel = computed(() => !!this.hbLabel() || this.projectedLabel());

  protected readonly classes = computed(() =>
    cn(
      dividerVariants({
        orientation: this.hbOrientation(),
        variant: this.hbVariant(),
        labeled: this.hasLabel(),
      }),
      this.class(),
    ),
  );

  constructor() {
    const read = (): boolean => (this.host.nativeElement.textContent ?? '').trim().length > 0;
    this.projectedLabel.set(read());
    afterNextRender(() => this.projectedLabel.set(read()));
  }
}

import { cva, type VariantProps } from 'class-variance-authority';

export const dividerVariants = cva('shrink-0 border-border', {
  variants: {
    orientation: {
      horizontal: 'w-full border-t',
      vertical: 'h-full self-stretch border-l',
    },
    variant: { solid: 'border-solid', dashed: 'border-dashed', dotted: 'border-dotted' },
    labeled: { true: 'flex items-center border-0', false: '' },
  },
  compoundVariants: [
    {
      labeled: true,
      orientation: 'horizontal',
      class:
        "w-full before:h-0 before:flex-1 before:border-t before:border-border before:content-[''] after:h-0 after:flex-1 after:border-t after:border-border after:content-['']",
    },
    {
      labeled: true,
      orientation: 'vertical',
      class:
        "min-h-full w-fit flex-col before:w-0 before:flex-1 before:border-l before:border-border before:content-[''] after:w-0 after:flex-1 after:border-l after:border-border after:content-['']",
    },
    { labeled: true, variant: 'dashed', class: 'before:border-dashed after:border-dashed' },
    { labeled: true, variant: 'dotted', class: 'before:border-dotted after:border-dotted' },
  ],
  defaultVariants: { orientation: 'horizontal', variant: 'solid', labeled: false },
});

export type HbDividerOrientation = NonNullable<VariantProps<typeof dividerVariants>['orientation']>;
export type HbDividerVariant = NonNullable<VariantProps<typeof dividerVariants>['variant']>;

export * from './divider.component';
export * from './divider.variants';
export * from './divider.imports';

