import { ChangeDetectionStrategy, Component } from '@angular/core';

import { HbBadgeImports, HbDividerImports } from '@herbst/ui';

@Component({
  selector: 'hb-demo-divider-labeled',
  imports: [HbDividerImports, HbBadgeImports],
  template: `
    <div class="flex w-full max-w-md flex-col gap-6">
      <hb-divider hbLabel="Autumn" />

      <hb-divider>
        <span hb-badge hbType="outline" class="font-mono uppercase tracking-[0.08em]">or</span>
      </hb-divider>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoDividerLabeledComponent {}

import { ChangeDetectionStrategy, Component } from '@angular/core';

import { HbDividerImports } from '@herbst/ui';

@Component({
  selector: 'hb-demo-divider-variants',
  imports: [HbDividerImports],
  template: `
    <div class="flex w-full max-w-md flex-col gap-4 text-sm text-muted-foreground">
      <span>Solid divider below</span>
      <hb-divider />
      <span>Dashed divider below</span>
      <hb-divider hbVariant="dashed" />
      <span>Dotted divider below</span>
      <hb-divider hbVariant="dotted" />
      <span>End</span>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoDividerVariantsComponent {}

import { ChangeDetectionStrategy, Component } from '@angular/core';

import { HbDividerImports } from '@herbst/ui';

@Component({
  selector: 'hb-demo-divider-vertical',
  imports: [HbDividerImports],
  template: `
    <div class="flex h-8 items-center gap-4 text-sm text-foreground">
      <span>Oak</span>
      <hb-divider hbOrientation="vertical" />
      <span>Beech</span>
      <hb-divider hbOrientation="vertical" hbVariant="dashed" />
      <span>Maple</span>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoDividerVerticalComponent {}
